using Contoso.Scoring;

namespace Contoso.Scoring.Tests;

[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calculator = new();

    // --- CalculatePercentage tests ---

    [TestMethod]
    [DataRow(7, 10, 70.0)]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 5, 0.0)]
    [DataRow(1, 3, 33.333333333333336)]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(int correct, int total, double expected)
    {
        var result = _calculator.CalculatePercentage(correct, total);
        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void CalculatePercentage_Result_IsInValidRange()
    {
        var result = _calculator.CalculatePercentage(8, 10);

        // Assert.IsInRange verifies: low <= actual <= high
        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void CalculatePercentage_MostCorrect_IsGreaterThanHalf()
    {
        var result = _calculator.CalculatePercentage(9, 10);

        // Assert.IsGreaterThan verifies: actual > lowerBound
        Assert.IsGreaterThan(50.0, result);
    }

    [TestMethod]
    public void CalculatePercentage_FewCorrect_IsLessThanHalf()
    {
        var result = _calculator.CalculatePercentage(1, 10);

        // Assert.IsLessThan verifies: actual < upperBound
        Assert.IsLessThan(50.0, result);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(11, 10));
    }

    // --- GetGrade boundary tests ---

    [TestMethod]
    [DataRow(100.0, "A")]
    [DataRow(90.0, "A")]
    [DataRow(89.99, "B")]
    [DataRow(80.0, "B")]
    [DataRow(79.99, "C")]
    [DataRow(70.0, "C")]
    [DataRow(69.99, "D")]
    [DataRow(60.0, "D")]
    [DataRow(59.99, "F")]
    [DataRow(0.0, "F")]
    public void GetGrade_AtBoundaries_ReturnsCorrectGrade(double percentage, string expected)
    {
        var grade = _calculator.GetGrade(percentage);
        Assert.AreEqual(expected, grade);
    }

    // --- NormalizeScore tests ---

    [TestMethod]
    public void NormalizeScore_MidRange_IsInExpectedRange()
    {
        var result = _calculator.NormalizeScore(45, 100);

        // Verify the normalized score falls within [0, 100]
        Assert.IsInRange(result, 0.0, 100.0);
        Assert.AreEqual(45.0, result);
    }

    [TestMethod]
    public void NormalizeScore_HighRaw_IsCappedAt100()
    {
        // Raw score exceeds max — should cap at 100
        var result = _calculator.NormalizeScore(150, 100);

        Assert.AreEqual(100.0, result);
        Assert.IsLessThan(100.1, result);
    }

    [TestMethod]
    public void NormalizeScore_PositiveInput_IsGreaterThanZero()
    {
        var result = _calculator.NormalizeScore(1, 100);

        Assert.IsGreaterThan(0.0, result);
    }

    [TestMethod]
    public void NormalizeScore_NegativeRaw_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(-1, 100));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(50, 0));
    }

    [TestMethod]
    [DynamicData(nameof(NormalizeScoreRangeData))]
    public void NormalizeScore_VariousInputs_AlwaysInRange(double raw, double max)
    {
        var result = _calculator.NormalizeScore(raw, max);

        Assert.IsInRange(result, 0.0, 100.0);
    }

    public static IEnumerable<(double raw, double max)> NormalizeScoreRangeData =>
    [
        (0, 100),
        (50, 100),
        (100, 100),
        (200, 100),
        (1, 1000),
    ];
}

